const INPUT: &[u8] = b"";
const WINDOW_SIZE: usize = 14;

fn jump_position(window: &[u8]) -> Option<usize> {
    for index in (1..WINDOW_SIZE).rev() {
        for index2 in (0..index).rev() {
            if window[index] == window[index2] {
                return Some(index2 + 1);
            }
        }
    }
    None
}

fn main() {
    let mut index = 0;
    loop {
        if let Some(jump) = jump_position(&INPUT[index..index + WINDOW_SIZE]) {
            index += jump;
        } else {
            println!("{}", index + WINDOW_SIZE);
            break;
        }
    }
}
